9	
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library vunit_lib;
15	use vunit_lib.check_pkg.all;
16	use vunit_lib.run_pkg.all;
17	
18	library common;
19	use common.time_pkg.to_real_s;
20	
21	
22	entity tb_resync_twophase is
23	  generic (
24	    output_clock_is_greatly_faster : boolean := false;
25	    output_clock_is_mildly_faster : boolean := false;
26	    clocks_are_same : boolean := false;
27	    output_clock_is_mildly_slower : boolean := false;
28	    output_clock_is_greatly_slower : boolean := false;
29	    enable_lutram : boolean;
30	    enable_output_register : boolean := false;
31	    runner_cfg : string
32	  );
33	end entity;
34	
35	architecture tb of tb_resync_twophase is
36	
37	  -- Big difference, so that erroneous level resync back or forth could happen.
38	  constant clock_period_greatly_fast : time := 2 ns;
39	  constant clock_period_mildly_fast : time := clock_period_greatly_fast * 20;
40	  constant clock_period_medium : time := clock_period_mildly_fast + 1 ns;
41	  constant clock_period_mildly_slow : time := clock_period_medium + 1 ns;
42	  constant clock_period_greatly_slow : time := clock_period_medium * 20 + 1 ns;
43	
44	  function get_clk_out_period return time is
45	  begin
