-- -------------------------------------------------------------------------------------------------
-- Copyright (c) Lukas Vik. All rights reserved.
--
-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
-- peer-reviewed VHDL building blocks.
-- https://hdl-modules.com
-- https://github.com/hdl-modules/hdl-modules
-- -------------------------------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

library vunit_lib;
use vunit_lib.check_pkg.all;
use vunit_lib.run_pkg.all;

library common;
use common.time_pkg.to_real_s;


entity tb_resync_twophase is
  generic (
    output_clock_is_greatly_faster : boolean := false;
    output_clock_is_mildly_faster : boolean := false;
    clocks_are_same : boolean := false;
    output_clock_is_mildly_slower : boolean := false;
    output_clock_is_greatly_slower : boolean := false;
    enable_lutram : boolean;
    enable_output_register : boolean := false;
    runner_cfg : string
  );
end entity;

architecture tb of tb_resync_twophase is

  -- Big difference, so that erroneous level resync back or forth could happen.
  constant clock_period_greatly_fast : time := 2 ns;
  constant clock_period_mildly_fast : time := clock_period_greatly_fast * 20;
  constant clock_period_medium : time := clock_period_mildly_fast + 1 ns;
  constant clock_period_mildly_slow : time := clock_period_medium + 1 ns;
  constant clock_period_greatly_slow : time := clock_period_medium * 20 + 1 ns;

  function get_clk_out_period return time is
  begin
    if output_clock_is_greatly_faster then
      return clock_period_greatly_fast;
    end if;

    if output_clock_is_mildly_faster then
      return clock_period_mildly_fast;
    end if;

    if output_clock_is_mildly_slower then
      return clock_period_mildly_slow;
    end if;

    if output_clock_is_greatly_slower then
      return clock_period_greatly_slow;
    end if;

    if clocks_are_same then
      return clock_period_medium;
    end if;

    assert false;
  end function;
  constant clk_in_period : time := clock_period_medium;
  constant clk_out_period : time := get_clk_out_period;

  signal clk_in, clk_out : std_ulogic := '0';

  constant data_init : u_unsigned(16 - 1 downto 0) := x"5A5A";
  signal data_in, data_out : u_unsigned(data_init'range) := data_init;

  signal num_outputs_checked : natural := 0;

  signal sum_cycles_since_last_change : natural := 0;
  signal min_cycles_since_last_change : positive := 2**20;
  signal max_cycles_since_last_change : positive := 1;

  signal sum_value_diff : natural := 0;
  signal min_value_diff : positive := 2 ** 20;
  signal max_value_diff : positive := 1;

begin

  clk_in <= not clk_in after clk_in_period / 2;
  clk_out <= not clk_out after clk_out_period / 2;

  test_runner_watchdog(runner, 10 ms);


  ------------------------------------------------------------------------------
  main : process
    constant num_tests : positive := 100;

    variable average_value_diff, average_cycles_since_last_change : real := 0.0;

    constant expected_time : time := 3 * clk_out_period + 3 * clk_in_period;
    variable got_time : time := 0 fs;
    variable relative_error : real := 0.0;
  begin
    test_runner_setup(runner, runner_cfg);

    report "clk_in_period: " & to_string(clk_in_period);
    report "clk_out_period: " & to_string(clk_out_period);

    -- Default value
    check_equal(data_out, data_init);

    wait until num_outputs_checked = num_tests and rising_edge(clk_out);

    average_value_diff := real(sum_value_diff) / real(num_outputs_checked);

    average_cycles_since_last_change := (
      real(sum_cycles_since_last_change) / real(num_outputs_checked)
    );

    got_time := average_cycles_since_last_change * clk_out_period;

    relative_error := abs(to_real_s(got_time - expected_time)) / to_real_s(expected_time);

    report "min_value_diff: " & to_string(min_value_diff);
    report "max_value_diff: " & to_string(max_value_diff);

    report "sum_value_diff: " & to_string(sum_value_diff);

    report "average_value_diff: " & to_string(average_value_diff);

    report "min_cycles_since_last_change: " & to_string(min_cycles_since_last_change);
    report "max_cycles_since_last_change: " & to_string(max_cycles_since_last_change);

    report "sum_cycles_since_last_change: " & to_string(sum_cycles_since_last_change);
    report "num_result_checked: " & to_string(num_outputs_checked);

    report "average_cycles_since_last_change: " & to_string(average_cycles_since_last_change);

    report "expected_time: " & to_string(expected_time);
    report "got_time: " & to_string(got_time);

    report "relative_error: " & to_string(100.0 * relative_error);
    assert relative_error < 0.16 report "Not expected throughput";

    test_runner_cleanup(runner);
  end process;


  ------------------------------------------------------------------------------
  stimuli : process
  begin
    wait until rising_edge(clk_in);

    data_in <= data_in + 1;
  end process;


  ------------------------------------------------------------------------------
  check_output_block : block
    signal data_out_p1 : u_unsigned(16 - 1 downto 0) := data_init;
    signal cycles_since_last_change : natural := 0;
  begin

    ------------------------------------------------------------------------------
    check_output : process
      variable value_diff : positive := 1;
    begin
      wait until rising_edge(clk_out);

      if data_out /= data_out_p1 then
        assert data_out > data_out_p1 report "data should be increasing";
        assert data_out < data_in report "output should be delayed input";

        value_diff := to_integer(data_out - data_out_p1);

        sum_value_diff <= sum_value_diff + value_diff;
        min_value_diff <= minimum(min_value_diff, value_diff);
        max_value_diff <= maximum(max_value_diff, value_diff);

        sum_cycles_since_last_change <= sum_cycles_since_last_change + cycles_since_last_change;

        min_cycles_since_last_change <= minimum(
          min_cycles_since_last_change, cycles_since_last_change
        );
        max_cycles_since_last_change <= maximum(
          max_cycles_since_last_change, cycles_since_last_change
        );

        cycles_since_last_change <= 1;

        num_outputs_checked <= num_outputs_checked + 1;

      else
        cycles_since_last_change <= cycles_since_last_change + 1;
      end if;

      data_out_p1 <= data_out;
    end process;

  end block;


  ------------------------------------------------------------------------------
  dut_gen : if enable_lutram generate

    ------------------------------------------------------------------------------
    dut : entity work.resync_twophase_lutram
      generic map (
        width => data_in'length,
        default_value => std_ulogic_vector(data_init),
        enable_output_register => enable_output_register
      )
      port map (
        clk_in => clk_in,
        data_in => std_ulogic_vector(data_in),

        clk_out => clk_out,
        u_unsigned(data_out) => data_out
      );

  else generate

    ------------------------------------------------------------------------------
    dut : entity work.resync_twophase
      generic map (
        width => data_in'length,
        default_value => std_ulogic_vector(data_init)
      )
      port map (
        clk_in => clk_in,
        data_in => std_ulogic_vector(data_in),

        clk_out => clk_out,
        u_unsigned(data_out) => data_out
      );

    assert not enable_output_register;

  end generate;

end architecture;

# --------------------------------------------------------------------------------------------------
# Copyright (c) Lukas Vik. All rights reserved.
#
# This file is part of the hdl-modules project, a collection of reusable, high-quality,
# peer-reviewed VHDL building blocks.
# https://hdl-modules.com
# https://github.com/hdl-modules/hdl-modules
# --------------------------------------------------------------------------------------------------

from __future__ import annotations

from typing import TYPE_CHECKING, Any

from tsfpga.examples.vivado.project import TsfpgaExampleVivadoNetlistProject
from tsfpga.module import BaseModule
from tsfpga.vivado.build_result_checker import EqualTo, Ffs, LutRams, MaximumLogicLevel, TotalLuts

if TYPE_CHECKING:
    from vunit.ui import VUnit


class Module(BaseModule):
    def setup_vunit(
        self,
        vunit_proj: VUnit,
        **kwargs: Any,  # noqa: ANN401, ARG002
    ) -> None:
        self.setup_resync_counter_tests(vunit_proj=vunit_proj)
        self.setup_resync_cycles_tests(vunit_proj=vunit_proj)
        self.setup_resync_pulse_tests(vunit_proj=vunit_proj)
        self.setup_resync_slv_level_tests(vunit_proj=vunit_proj)
        self.setup_resync_twophase_tests(vunit_proj=vunit_proj)
        self.setup_resync_twophase_handshake_tests(vunit_proj=vunit_proj)

    def setup_resync_counter_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_counter")
        for pipeline_output in [True, False]:
            generics = {"pipeline_output": pipeline_output}
            self.add_vunit_config(tb, generics=generics)

    def setup_resync_cycles_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_cycles")
        for active_high in [True, False]:
            generics = {"active_high": active_high, "output_clock_is_faster": True}
            self.add_vunit_config(tb, generics=generics)

            generics = {"active_high": active_high}
            self.add_vunit_config(tb, generics=generics)

            generics = {"active_high": active_high, "output_clock_is_slower": True}
            self.add_vunit_config(tb, generics=generics)

    def setup_resync_pulse_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_pulse")
        for enable_feedback in [True, False]:
            for active_level in [True, False]:
                for input_pulse_overload in [True, False]:
                    for mode in [
                        "output_clock_is_faster",
                        "output_clock_is_slower",
                        "clocks_are_same",
                    ]:
                        generics = {
                            "enable_feedback": enable_feedback,
                            "input_pulse_overload": input_pulse_overload,
                            "active_level": active_level,
                        }
                        generics[mode] = True
                        self.add_vunit_config(tb, generics=generics)

    def setup_resync_slv_level_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_slv_level")
        for output_clock_is_faster in [True, False]:
            for enable_input_register in [True, False]:
                generics = {
                    "output_clock_is_faster": output_clock_is_faster,
                    "enable_input_register": enable_input_register,
                }
                self.add_vunit_config(tb, generics=generics)

    def setup_resync_twophase_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_twophase")
        for mode in [
            "output_clock_is_greatly_faster",
            "output_clock_is_mildly_faster",
            "clocks_are_same",
            "output_clock_is_mildly_slower",
            "output_clock_is_greatly_slower",
        ]:
            for enable_lutram in [False, True]:
                generics = {mode: True, "enable_lutram": enable_lutram}

                if enable_lutram:
                    for enable_output_register in [False, True]:
                        generics["enable_output_register"] = enable_output_register
                        self.add_vunit_config(tb, generics=generics)
                else:
                    self.add_vunit_config(tb, generics=generics)

    def setup_resync_twophase_handshake_tests(self, vunit_proj: VUnit) -> None:
        tb = vunit_proj.library(self.library_name).test_bench("tb_resync_twophase_handshake")
        for mode in [
            "result_clock_is_greatly_faster",
            "result_clock_is_mildly_faster",
            "clocks_are_same",
            "result_clock_is_mildly_slower",
            "result_clock_is_greatly_slower",
        ]:
            generics = {mode: True}

            for test in tb.get_tests():
                if test.name == "test_random_data":
                    for data_width in [8, 16]:
                        generics["data_width"] = data_width
                        self.add_vunit_config(test, generics=generics)

                elif test.name == "test_count_sampling_period":
                    generics["stall_probability_percent"] = 0
                    self.add_vunit_config(test, generics=generics)

                elif test.name == "test_init_state":
                    self.add_vunit_config(test, generics=generics)

                else:
                    raise RuntimeError(f"Unknown test: {test.name}")

    def get_build_projects(self) -> list[TsfpgaExampleVivadoNetlistProject]:
        # Import locally, for performance in the typical use case.
        from dataclasses import dataclass  # noqa: PLC0415

        # The 'hdl_modules' Python package is probably not on the PYTHONPATH in most scenarios where
        # this module is used. Hence we can not import at the top of this file.
        # This method is only called when running netlist builds in the hdl-modules repo from the
        # bundled tools/build_fpga.py, where PYTHONPATH is correctly set up.
        from hdl_modules import get_hdl_modules  # noqa: PLC0415

        projects = []
        modules = get_hdl_modules(names_include=[self.name, "common", "math"])
        part = "xc7z020clg400-1"

        for enable_feedback in [False, True]:
            generics = {"enable_feedback": enable_feedback}
            projects.append(
                TsfpgaExampleVivadoNetlistProject(
                    name=self.netlist_build_name("resync_pulse", generics=generics),
                    modules=modules,
                    part=part,
                    top="resync_pulse",
                    generics=generics,
                    build_result_checkers=[
                        TotalLuts(EqualTo(2 + 1 * enable_feedback)),
                        Ffs(EqualTo(4 + 3 * enable_feedback)),
                    ],
                )
            )

        @dataclass
        class Config:
            name: str
            lut: int
            ff: int
            logic: int
            width: int | None = None
            data_width: int | None = None
            counter_width: int | None = None

        def add_config(config: Config) -> None:
            if config.width is not None:
                generics = {"width": config.width}
            elif config.data_width is not None:
                generics = {"data_width": config.data_width}
            elif config.counter_width is not None:
                generics = {"counter_width": config.counter_width}
            else:
                raise ValueError("Invalid config")

            build_result_checkers = [
                Ffs(EqualTo(config.ff)),
                MaximumLogicLevel(EqualTo(config.logic)),
            ]
            if "lutram" in config.name:
                num_lutrams = {8: 8, 16: 12, 24: 16, 32: 24, 64: 44}
                width = config.width if config.width is not None else config.data_width
                num_lutram = num_lutrams[width]

                build_result_checkers.append(LutRams(EqualTo(num_lutram)))
                build_result_checkers.append(TotalLuts(EqualTo(num_lutram + config.lut)))
            else:
                build_result_checkers.append(LutRams(EqualTo(0)))
                build_result_checkers.append(TotalLuts(EqualTo(config.lut)))

            projects.append(
                TsfpgaExampleVivadoNetlistProject(
                    name=self.netlist_build_name(config.name, generics),
                    modules=modules,
                    part=part,
                    top=config.name,
                    generics=generics,
                    build_result_checkers=build_result_checkers,
                )
            )

        add_config(Config(name="resync_counter", width=8, lut=11, ff=24, logic=3))
        add_config(Config(name="resync_counter", width=16, lut=23, ff=48, logic=4))
        add_config(Config(name="resync_counter", width=24, lut=35, ff=72, logic=6))
        add_config(Config(name="resync_counter", width=32, lut=59, ff=96, logic=3))
        add_config(Config(name="resync_counter", width=64, lut=123, ff=192, logic=4))

        add_config(Config(name="resync_cycles", counter_width=8, lut=26, ff=41, logic=5))
        add_config(Config(name="resync_cycles", counter_width=16, lut=31, ff=81, logic=7))
        add_config(Config(name="resync_cycles", counter_width=24, lut=45, ff=121, logic=9))
        add_config(Config(name="resync_cycles", counter_width=32, lut=69, ff=161, logic=9))
        add_config(Config(name="resync_cycles", counter_width=64, lut=140, ff=321, logic=17))

        for width in [8, 16, 24, 32, 64]:
            add_config(
                Config(
                    name="resync_rarely_valid",
                    data_width=width,
                    lut=2,
                    ff=2 * width + 5,
                    logic=2,
                )
            )

            add_config(
                Config(name="resync_rarely_valid_lutram", data_width=width, lut=2, ff=4, logic=2)
            )

            add_config(
                Config(name="resync_twophase", width=width, lut=3, ff=2 * width + 6, logic=2)
            )

            add_config(Config(name="resync_twophase_lutram", width=width, lut=2, ff=6, logic=2))

            add_config(
                Config(
                    name="resync_twophase_handshake",
                    data_width=width,
                    lut=5,
                    ff=2 * width + 8,
                    logic=2,
                )
            )

        return projects

