152	      wait until
153	        read_valid'event or write_ready'event or almost_full'event or almost_empty'event
154	        for 1 us;
155	
156	      check_equal(read_valid, '0');
157	      check_equal(write_ready, '1');
158	      check_equal(almost_full, '0');
159	      check_equal(almost_empty, '1');
160	
161	    elsif run("test_write_faster_than_read") then
162	      for packet_idx in 0 to 1000 loop
163	        run_test(num_beats=>rnd.Uniform(1, 5));
164	      end loop;
165	
166	      wait_until_done;
167	      check_relation(has_gone_full_times > 500, "Got " & to_string(has_gone_full_times));
168	
169	    elsif run("test_read_faster_than_write") then
170	      for packet_idx in 0 to 1000 loop
171	        run_test(num_beats=>rnd.Uniform(1, 5));
172	      end loop;
